framework_css:
/*
  Kent Storage Base Framework Styles
  - Matches the provided Rental Info/Payment design
  - Reusable across all pages (header, footer, and global layout)
*/

/* ===== CSS Reset & Base ===== */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  padding: 0;
  font-family: 'Source Sans 3', Arial, sans-serif;
  font-weight: 400;
  line-height: 1.5;
  color: #333333;
  background-color: #ffffff;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus {
  outline: 2px solid #d64025;
  outline-offset: 3px;
}

ul,
ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

p {
  margin: 0;
}

/* ===== Design System ===== */
:root {
  /* Colors from palette */
  --color-primary-red: #d64025;
  --color-primary-dark: #333333;
  --color-secondary-tan: #cbb68a;
  --color-secondary-gray: #555555;
  --color-accent-red: #cc0000;

  --color-neutral-white: #ffffff;
  --color-neutral-offwhite: #f5f5f5;
  --color-neutral-black: #000000;

  --color-success: #2e7d32;
  --color-error: #c62828;
  --color-warning: #ed6c02;
  --color-info: #1565c0;

  /* Typography */
  --font-logo: 'Playfair Display', 'Times New Roman', serif;
  --font-heading: 'Space Grotesk', Helvetica, Arial, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --font-size-h1: 2.125rem; /* ~34px */
  --font-size-h2: 1.875rem; /* ~30px */
  --font-size-h3: 1.25rem;  /* ~20px */
  --font-size-body: 0.9375rem; /* 15px */
  --font-size-small: 0.8125rem; /* 13px */

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-xxs: 0.25rem; /* 4px */
  --space-xs: 0.5rem;   /* 8px */
  --space-sm: 1rem;     /* 16px */
  --space-md: 1.5rem;   /* 24px */
  --space-lg: 2rem;     /* 32px */
  --space-xl: 3rem;     /* 48px */
  --space-xxl: 4rem;    /* 64px */

  /* Layout */
  --layout-max-width: 960px;
}

body {
  font-size: var(--font-size-body);
}

/* ===== Layout Helpers ===== */
.container {
  width: 100%;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding-left: var(--space-md);
  padding-right: var(--space-md);
}

.site-main {
  min-height: 40vh;
}

.main-content {
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xl);
}

/* ===== Header ===== */
.site-header {
  background-color: var(--color-neutral-white);
  border-bottom: 0;
}

.header-inner {
  padding-top: var(--space-xl);
  padding-bottom: var(--space-md);
  display: flex;
  flex-direction: column;
  align-items: center;
}

/* Logo */
.site-logo {
  font-family: var(--font-logo);
  font-size: 2.25rem; /* ~36px */
  font-weight: 400;
  letter-spacing: 0.12em;
  color: var(--color-primary-red);
  text-transform: none;
}

.site-logo:hover {
  color: var(--color-accent-red);
}

/* Primary Navigation */
.primary-nav {
  margin-top: var(--space-lg);
}

.nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 3.5rem; /* generous spacing between items, matches design */
}

.nav-link {
  position: relative;
  display: inline-block;
  padding-bottom: var(--space-xs);
  font-family: var(--font-heading);
  font-size: 0.8125rem; /* small, compact nav text */
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--color-neutral-black);
}

.nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 0.125rem; /* 2px */
  background-color: transparent;
}

.nav-link:hover {
  color: var(--color-primary-dark);
}

.nav-link--active::after {
  background-color: var(--color-neutral-black); /* bold underline for active item */
}

.nav-link:focus-visible {
  outline: 2px solid var(--color-primary-red);
  outline-offset: 4px;
}

/* ===== Page Header Bar ===== */
.page-header-bar {
  background-color: var(--color-primary-dark); /* #333333 */
  color: var(--color-neutral-white);
}

.page-header-bar .container {
  padding-top: var(--space-md);
  padding-bottom: var(--space-md);
}

.page-title {
  margin: 0;
  text-align: center;
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-tight);
}

/* ===== Footer ===== */
.site-footer {
  background-color: var(--color-neutral-offwhite);
  border-top: 1px solid #e0e0e0;
  margin-top: var(--space-xl);
}

.footer-inner {
  padding-top: var(--space-lg);
  padding-bottom: var(--space-lg);
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: var(--space-md);
}

.footer-logo {
  font-family: var(--font-logo);
  font-size: 1.25rem;
  letter-spacing: 0.12em;
  color: var(--color-primary-red);
}

.footer-nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 2.5rem;
}

.footer-nav-link {
  font-family: var(--font-body);
  font-size: 0.8125rem;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-secondary-gray);
}

.footer-nav-link:hover {
  color: var(--color-primary-dark);
}

.footer-meta {
  font-size: var(--font-size-small);
  color: #777777;
}

.footer-copy {
  margin: 0;
}

/* ===== Responsive Adjustments ===== */
@media (max-width: 768px) {
  .header-inner {
    padding-top: var(--space-lg);
    padding-bottom: var(--space-sm);
  }

  .nav-list {
    gap: 1.75rem;
  }

  .page-header-bar .container {
    padding-top: var(--space-sm);
    padding-bottom: var(--space-sm);
  }

  .page-title {
    font-size: 1.75rem;
  }

  .footer-nav-list {
    gap: 1.5rem;
  }
}

@media (max-width: 480px) {
  .site-logo {
    font-size: 1.875rem;
  }

  .nav-link {
    letter-spacing: 0.16em;
  }

  .container {
    padding-left: var(--space-sm);
    padding-right: var(--space-sm);
  }
}
